-- Parse database: lazy load per huruf
local WORDS_CACHE = {}
local function getWords(letter)
    if WORDS_CACHE[letter] then return WORDS_CACHE[letter] end
    local raw = _WD[letter]
    if not raw then WORDS_CACHE[letter] = {}; return {} end
    local t = {}
    for w in raw:gmatch("[^|]+") do
        if #w >= 2 then t[#t+1] = w end
    end
    WORDS_CACHE[letter] = t
    return t
end

-- ==========================================
-- WORD AI SELECTOR
-- ==========================================
local usedWords = {}

local function scoreWord(w)
    local score = 0
    local last = w:sub(-1):lower()
    if CONFIG.BEST_ENDINGS[last] then score = score + 100 end
    if CONFIG.BAD_ENDINGS[last]  then score = score - 50  end
    score = score + #w * 2
    return score
end

-- Cari N kata terbaik untuk huruf tertentu
local function findTopWords(letter, n)
    letter = letter:lower()
    local pool = {}
    local seen = {}
    local src  = getWords(letter)
    n = n or 5

    for _, w in ipairs(src) do
        if #w >= 3 and not seen[w] and not usedWords[w] then
            seen[w] = true; pool[#pool+1] = w
        end
    end
    -- Reset jika habis
    if #pool == 0 then
        for _, w in ipairs(src) do
            if #w >= 3 and not seen[w] then
                usedWords[w] = nil; seen[w] = true; pool[#pool+1] = w
            end
        end
    end
    if #pool == 0 then return {} end

    local scored = {}
    for _, w in ipairs(pool) do
        scored[#scored+1] = {word=w, score=scoreWord(w)+math.random(1,8)}
    end
    table.sort(scored, function(a,b) return a.score > b.score end)

    local result = {}
    for i = 1, math.min(n, #scored) do
        result[i] = scored[i].word
    end
    return result
end

local function findBestWord(letter)
    local top = findTopWords(letter, 5)
    if #top == 0 then return nil end
    local chosen = top[math.random(1, math.min(3,#top))]
    usedWords[chosen] = true
    return chosen
end

-- ==========================================
-- DETECT HURUF DARI GAME
-- ==========================================
local lastDetectedWord = ""

local function getDescendants()
    local res = {}
    for _, g in ipairs(playerGui:GetChildren()) do
        if g.Name ~= "SK_YURXZ" then
            for _, o in ipairs(g:GetDescendants()) do
                res[#res+1] = o
            end
        end
    end
    return res
end

local function getCurrentLetter()
    local objs = getDescendants()

    -- Strategi 1: nama label mengandung kata kunci game
    local nameKeys = {"currentword","lastword","wordlabel","current_word","last_word","wordtext","kataterakhir","katatampil","katasekarang","wordshow","activelabel","turnword","currentkata","wordlbl","wordvalue","answerword","letterstart","startletter"}
    for _, obj in ipairs(objs) do
        if obj:IsA("TextLabel") and obj.Visible then
            local nlow = obj.Name:lower():gsub("[^a-z]","")
            for _, kw in ipairs(nameKeys) do
                if nlow == kw or nlow:find(kw,1,true) then
                    local t = obj.Text:lower():gsub("[^a-z]","")
                    if #t >= 2 then return t:sub(-1) end
                end
            end
        end
    end

    -- Strategi 2: label besar berisi 1 kata
    local candidates = {}
    for _, obj in ipairs(objs) do
        if obj:IsA("TextLabel") and obj.Visible then
            local t = obj.Text:lower():gsub("[^a-z]","")
            if #t >= 3 and #t <= 25 then
                local area = obj.AbsoluteSize.X * obj.AbsoluteSize.Y
                if area > 800 then
                    candidates[#candidates+1] = {t=t, area=area, raw=obj.Text}
                end
            end
        end
    end
    table.sort(candidates, function(a,b) return a.area > b.area end)
    for _, c in ipairs(candidates) do
        if not c.raw:match("^%u+$") and not c.raw:find("SAMBUNG") and not c.raw:find("KATA") then
            local last = c.t:sub(-1)
            if last:match("[a-z]") and c.t ~= lastDetectedWord then
                return last
            end
        end
    end

    -- Strategi 3: pola teks "Huruf: X" dll
    for _, obj in ipairs(objs) do
        if obj:IsA("TextLabel") and obj.Visible then
            local t = obj.Text
            local found =
                t:match("[Hh]uruf%s*:%s*([A-Za-z])") or
                t:match("[Mm]ulai%s+[Dd]ari%s*:%s*([A-Za-z])") or
                t:match("[Ss]tart%s*:%s*([A-Za-z])") or
                t:match("[Aa]wali%s+[Dd]engan%s*:%s*([A-Za-z])")
            if found then return found:lower() end
        end
    end

    -- Strategi 4: label 1 huruf besar
    for _, obj in ipairs(objs) do
        if obj:IsA("TextLabel") and obj.Visible then
            local t = obj.Text:gsub("%s+","")
            if #t == 1 and t:match("[A-Za-z]") and obj.AbsoluteSize.X > 20 then
                return t:lower()
            end
        end
    end

    return nil
end

-- ==========================================
-- CARI TEXTBOX & TOMBOL SUBMIT
-- ==========================================
local function findInputBox()
    local objs = getDescendants()
    local nameKeys = {"input","answer","jawab","kata","word","text","chat","typehere","typebox","inputbox","answerbox","wordbox","inputfield","textfield","chatbox","entry"}
    local cands = {}
    for _, obj in ipairs(objs) do
        if obj:IsA("TextBox") and obj.Visible then
            local n = obj.Name:lower()
            local score = 0
            for _, kw in ipairs(nameKeys) do
                if n:find(kw,1,true) then score = score + 10; break end
            end
            if obj.Text == "" then score = score + 3 end
            cands[#cands+1] = {obj=obj, score=score}
        end
    end
    table.sort(cands, function(a,b) return a.score > b.score end)
    if #cands > 0 then return cands[1].obj end
    return nil
end

local function findSubmitBtn()
    local objs = getDescendants()
    for _, obj in ipairs(objs) do
        if obj:IsA("TextButton") and obj.Visible then
            local n = obj.Name:lower()
            local t = obj.Text:lower():gsub("%s+","")
            if n=="enter" or n:find("enter") or n:find("submit") or n:find("kirim")
            or t=="enter" or t=="kirim" or t=="submit" or t=="ok" then
                return obj
            end
        end
    end
    return nil
end

-- ==========================================
-- HIDE / SHOW KEYBOARD (mobile)
-- ==========================================
local function hideKeyboard()
    if not CONFIG.HIDE_KB then return end
    -- Fokus ke TextBox dummy tak terlihat = keyboard dismiss
    pcall(function()
        local dummy = Instance.new("TextBox")
        dummy.Size = UDim2.new(0,1,0,1)
        dummy.Position = UDim2.new(0,-100,0,-100)
        dummy.BackgroundTransparency = 1
        dummy.TextTransparency = 1
        dummy.Parent = playerGui
        dummy:CaptureFocus()
        task.wait(0.05)
        dummy:ReleaseFocus()
        dummy:Destroy()
    end)
end

-- ==========================================
-- SUBMIT KATA KE GAME
-- ==========================================
local function submitWord(word)
    if not word or #word == 0 then return false end
    local inputBox = findInputBox()

    if inputBox then
        pcall(function() inputBox:CaptureFocus() end)
        task.wait(0.04)
        inputBox.Text = ""
        task.wait(0.02)

        if CONFIG.NATURAL_TYPE then
            for i = 1, #word do
                inputBox.Text = word:sub(1,i)
                local d = CONFIG.SPEED_MIN + math.random()*(CONFIG.SPEED_MAX-CONFIG.SPEED_MIN)
                task.wait(d)
            end
        else
            inputBox.Text = word
            task.wait(0.05)
        end

        task.wait(0.08)

        if CONFIG.AUTO_SUBMIT then
            local sb = findSubmitBtn()
            if sb then
                pcall(function() sb.MouseButton1Click:Fire() end)
                task.wait(0.03)
                pcall(function()
                    local vim = game:GetService("VirtualInputManager")
                    local cx = sb.AbsolutePosition.X + sb.AbsoluteSize.X/2
                    local cy = sb.AbsolutePosition.Y + sb.AbsoluteSize.Y/2
                    vim:SendMouseButtonEvent(cx,cy,0,true,game,1)
                    task.wait(0.03)
                    vim:SendMouseButtonEvent(cx,cy,0,false,game,1)
                end)
            else
                pcall(function()
                    local vim = game:GetService("VirtualInputManager")
                    vim:SendKeyEvent(true,Enum.KeyCode.Return,false,game)
                    task.wait(0.04)
                    vim:SendKeyEvent(false,Enum.KeyCode.Return,false,game)
                end)
                pcall(function() inputBox.FocusLost:Fire(true) end)
            end
        end

        -- Sembunyikan keyboard setelah submit
        task.delay(0.2, hideKeyboard)
        return true
    else
        -- Keyboard fisik fallback
        pcall(function()
            local vim = game:GetService("VirtualInputManager")
            for i = 1, #word do
                local c = word:sub(i,i):upper()
                local kc = Enum.KeyCode[c]
                if kc then
                    vim:SendKeyEvent(true,kc,false,game)
                    task.wait(0.02)
                    vim:SendKeyEvent(false,kc,false,game)
                    task.wait(CONFIG.SPEED_MIN + math.random()*(CONFIG.SPEED_MAX-CONFIG.SPEED_MIN))
                end
            end
            task.wait(0.1)
            vim:SendKeyEvent(true,Enum.KeyCode.Return,false,game)
            task.wait(0.04)
            vim:SendKeyEvent(false,Enum.KeyCode.Return,false,game)
        end)
        task.delay(0.2, hideKeyboard)
        return true
    end
end

