-- ==========================================
-- UPDATE REKOMENDASI (mode manual)
-- ==========================================
local currentRekomWords = {}

local function updateRekoms(letter)
    local tops = findTopWords(letter, 5)
    currentRekomWords = tops
    for i, btn in ipairs(rekomBtns) do
        if tops[i] then
            btn.Text = tops[i] .. "  (akhir: " .. tops[i]:sub(-1):upper() .. ")"
            btn.Visible = true
            btn.BackgroundColor3 = C.card
            -- Warnai berdasarkan akhiran
            local last = tops[i]:sub(-1):lower()
            if CONFIG.BEST_ENDINGS[last] then
                Instance.new("UIStroke", btn).Color = C.green
            elseif CONFIG.BAD_ENDINGS[last] then
                Instance.new("UIStroke", btn).Color = C.red
            else
                Instance.new("UIStroke", btn).Color = C.border
            end
            -- Klik untuk submit
            btn.MouseButton1Click:Connect(function()
                local word = tops[i]
                if word then
                    usedWords[word] = true
                    kataLbl.Text = word
                    statusLbl.Text = "Mengirim: " .. word
                    statusLbl.TextColor3 = C.green
                    lastDetectedWord = word:lower():gsub("[^a-z]","")
                    task.spawn(function()
                        submitWord(word)
                        task.wait(0.8)
                        lastLetter = nil
                    end)
                end
            end)
        else
            btn.Visible = false
        end
    end
end

